public ObjectNode deserialize(JsonParser p, DeserializationContext ctxt) throws IOException
{
    if (p.getCurrentToken() == JsonToken.START_OBJECT) {
        p.nextToken();
        return deserializeObject(p, ctxt, ctxt.getNodeFactory());
    }
    // Handle cases where the parser is at the end of an object or in a state that indicates the object is complete or empty.
    if (p.getCurrentToken() == JsonToken.END_OBJECT || p.getCurrentToken() == JsonToken.VALUE_NULL) {
        return ctxt.getNodeFactory().objectNode();
    }
    // Add handling for other potential end-of-object states if necessary.
    throw ctxt.mappingException(ObjectNode.class);
}
